    "formulas": [
      "a(b+c)=ab+ac",
      "ax+b=0"
    ],
    "mistakes": [
      "Perkelia narį nepakeitęs ženklo — Iš abiejų pusių atimk 5.",
      "Sumaišo koeficientus su laisvaisiais nariais — 3x+2x=5x."
    ],
    "examples": [
      {
        "title": "Reiškinio sutvarkymas",
        "text": "Supaprastink 3x + 2x - x.",
        "solution": "Sudedame koeficientus. 3x+2x-x=(3+2-1)x Gauname. 4x",
        "answer": "4x"
      },
      {
        "title": "Lygties sprendimas",
        "text": "Išspręsk 2x + 5 = 17.",
        "solution": "Atimame 5 iš abiejų pusių. 2x=12 Daliname iš 2. x=6",
        "answer": "x=6"
      },
      {
        "title": "Nelygybė",
        "text": "Išspręsk 3x - 4 < 11.",
        "solution": "Pridedame 4. 3x<15 Daliname iš 3. x<5",
        "answer": "x<5"
      },
      {
        "title": "Modeliavimas",
        "text": "Bilietas kainuoja 4 eurus. Užrašyk lygtį, kai x bilietų kaina yra 20 eurų.",
        "solution": "Bendra kaina yra 4x. 4x=20 Išsprendžiame. x=5",
        "answer": "x=5"
      },
      {
        "title": "Formulė",
        "text": "Jei s = vt, rask t, kai s=96 ir v=12.",
        "solution": "Išreiškiame t. t=\\frac{s}{v} Įstatome duomenis. t=\\frac{96}{12}=8",
        "answer": "t=8"
      }
    ]
